     1→/**
     2→ * server/services/pythonPipeline.js — Bridge between Node.js and the Python AI pipeline.
     3→ * ========================================================================================
     4→ *
     5→ * PURPOSE:
     6→ *   Node.js cannot run Python code directly. This file acts as a bridge.
     7→ *   It manages a PERSISTENT Python HTTP server that stays running in the background.
     8→ *   Each resume is sent via HTTP POST and returns in ~200-500ms.
     9→ *
    10→ * ARCHITECTURE (new — persistent server):
    11→ *   1. On Node.js boot, startPythonServer() spawns pipeline_runner.py --serve
    12→ *   2. Python loads all heavy libraries (spaCy, sklearn) ONCE at startup (~5-8s)
    13→ *   3. Python prints {"status":"ready"} to stdout — Node.js detects this
    14→ *   4. For each resume, Node.js sends HTTP POST to localhost:5001
    15→ *   5. Python processes the resume (~200-500ms) and returns JSON
    16→ *   6. The Python process stays alive for all future requests
    17→ *
    18→ * PREVIOUS ARCHITECTURE (slow — ~15 seconds per resume):
    19→ *   - Spawned a NEW Python process for every single resume
    20→ *   - Python loaded spaCy + sklearn from scratch each time (~10-12s wasted)
    21→ *   - Process died after each resume, discarding all loaded state
    22→ *
    23→ * FALLBACK (Development Mode):
    24→ *   If Python isn't installed or the server can't start,
    25→ *   the function returns a mock result instead of crashing.
    26→ *
    27→ * CALLED BY:
    28→ *   server/routes/resumes.js      — on web upload
    29→ *   server/services/emailService.js — on email submission
    30→ *   server/index.js               — startPythonServer() on boot
    31→ */
    32→
    33→const { spawn } = require('child_process'); // Node.js built-in for spawning processes
    34→const path      = require('path');
    35→const fs        = require('fs');
    36→const http      = require('http');
    37→
    38→// Absolute path to the Python entry point script
    39→const PYTHON_SCRIPT = path.join(__dirname, '..', '..', 'pipeline_runner.py');
    40→
    41→// Port the Python server listens on (localhost only — not exposed externally)
    42→const PIPELINE_PORT = 5002;
    43→
    44→// ── Module-level state ───────────────────────────────────────────────────────
    45→let _pythonProcess = null;  // the child process running the Python server
    46→let _ready         = false; // has the Python server signaled readiness?
    47→let _starting      = null;  // Promise that resolves when the server is ready
    48→
    49→/**
    50→ * startPythonServer — Spawn the persistent Python AI pipeline server.
    51→ *
    52→ * Called ONCE on Node.js boot (from server/index.js).
    53→ * Starts pipeline_runner.py in --serve mode and waits for the "ready" signal.
    54→ *
    55→ * The Python process loads spaCy, sklearn, etc. once (~5-8 seconds on first boot).
    56→ * After that, every resume processes in ~200-500ms via HTTP.
    57→ *
    58→ * @returns {Promise<void>} - Resolves when the Python server is ready to accept requests
    59→ */
    60→const startPythonServer = () => {
    61→  // If already starting or started, return the existing promise
    62→  if (_starting) return _starting;
    63→  if (_ready) return Promise.resolve();
    64→
    65→  // If the Python script doesn't exist, skip
    66→  if (!fs.existsSync(PYTHON_SCRIPT)) {
    67→    console.warn('[pipeline] Python runner not found — will use mock data');
    68→    return Promise.resolve();
    69→  }
    70→
    71→  _starting = new Promise((resolve) => {
    72→    console.log('[pipeline] Starting persistent Python server...');
    73→
    74→    // Spawn: python pipeline_runner.py --serve --port 5001
    75→    const proc = spawn('python', [PYTHON_SCRIPT, '--serve', '--port', String(PIPELINE_PORT)], {
    76→      cwd: path.join(__dirname, '..', '..'),
    77→      stdio: ['ignore', 'pipe', 'pipe'], // stdin ignored, stdout/stderr piped
    78→    });
    79→
    80→    _pythonProcess = proc;
    81→
    82→    // Buffer for stdout data (the ready signal comes here)
    83→    let stdoutBuffer = '';
    84→
    85→    proc.stdout.on('data', (data) => {
    86→      const text = data.toString();
    87→      stdoutBuffer += text;
    88→
    89→      // Check for the readiness signal from Python
    90→      if (!_ready && stdoutBuffer.includes('"status": "ready"') || stdoutBuffer.includes('"status":"ready"')) {
    91→        _ready = true;
    92→        _starting = null;
    93→        console.log(`[pipeline] ✓ Python server ready on port ${PIPELINE_PORT}`);
    94→        resolve();
    95→      }
    96→
    97→      // Log any subsequent output from Python (processing logs)
    98→      if (_ready) {
    99→        const lines = text.trim().split('\n');
   100→        for (const line of lines) {
   101→          if (line && !line.includes('"status"')) {
   102→            console.log(`[python] ${line}`);
   103→          }
   104→        }
   105→      }
   106→    });
   107→
   108→    // Log Python stderr (warnings, errors, tracebacks)
   109→    proc.stderr.on('data', (data) => {
   110→      const text = data.toString().trim();
   111→      if (text) console.error(`[python-err] ${text}`);
   112→    });
   113→
   114→    // Handle process exit — auto-restart unless Node.js is shutting down
   115→    proc.on('close', (code) => {
   116→      console.warn(`[pipeline] Python process exited with code ${code}`);
   117→      _ready = false;
   118→      _pythonProcess = null;
   119→      _starting = null;
   120→
   121→      // Auto-restart after 2 seconds if the process crashed
   122→      if (code !== 0 && code !== null) {
   123→        console.log('[pipeline] Auto-restarting Python server in 2s...');
   124→        setTimeout(() => startPythonServer(), 2000);
   125→      }
   126→    });
   127→
   128→    proc.on('error', (err) => {
   129→      console.error('[pipeline] Failed to start Python:', err.message);
   130→      _ready = false;
   131→      _pythonProcess = null;
   132→      _starting = null;
   133→      resolve(); // resolve anyway — runPipeline will fall back to mock data
   134→    });
   135→
   136→    // If Python doesn't become ready within 30 seconds, give up waiting
   137→    // (it might still start later and auto-set _ready via stdout listener)
   138→    setTimeout(() => {
   139→      if (!_ready) {
   140→        console.warn('[pipeline] Python server did not become ready within 30s — using mock fallback');
   141→        _starting = null;
   142→        resolve();
   143→      }
   144→    }, 30000);
   145→  });
   146→
   147→  return _starting;
   148→};
   149→
   150→/**
   151→ * stopPythonServer — Gracefully shut down the Python server.
   152→ *
   153→ * Called during Node.js shutdown to clean up the child process.
   154→ */
   155→const stopPythonServer = () => {
   156→  if (_pythonProcess) {
   157→    _pythonProcess.kill('SIGTERM');
   158→    _pythonProcess = null;
   159→    _ready = false;
   160→    _starting = null;
   161→    console.log('[pipeline] Python server stopped');
   162→  }
   163→};
   164→
   165→// Clean up on Node.js exit
   166→process.on('exit', stopPythonServer);
   167→process.on('SIGINT', () => { stopPythonServer(); process.exit(0); });
   168→process.on('SIGTERM', () => { stopPythonServer(); process.exit(0); });
   169→
   170→
   171→/**
   172→ * runPipeline — Send a resume to the persistent Python server for processing.
   173→ *
   174→ * @param {string} filePath - Absolute path to the uploaded resume file
   175→ * @param {object} config   - Job requirements config (job_description, skills, etc.)
   176→ * @returns {Promise<object>} - Resolves with the extracted + scored candidate data
   177→ *
   178→ * Returned object shape:
   179→ *   { name, email, phone, skills, education, experience,
   180→ *     similarity, score, result, missingSkills, suggestions, strengths, weaknesses }
   181→ */
   182→const runPipeline = async (filePath, config = {}) => {
   183→  // Ensure the Python server is running
   184→  if (!_ready) {
   185→    await startPythonServer();
   186→  }
   187→
   188→  // If Python server still not ready (e.g. Python not installed), use mock data
   189→  if (!_ready) {
   190→    console.warn('[pipeline] Python server not available — using mock data');
   191→    return buildMockResult(filePath, config);
   192→  }
   193→
   194→  try {
   195→    const result = await sendToServer(filePath, config);
   196→
   197→    // Check if Python returned an error
   198→    if (result.error) {
   199→      console.error('[pipeline] Python error:', result.error);
   200→      return buildMockResult(filePath, config);
   201→    }
   202→
   203→    return result;
   204→
   205→  } catch (err) {
   206→    console.error('[pipeline] HTTP error:', err.message);
   207→
   208→    // If the connection was refused, the Python server might have crashed
   209→    // Try to restart it for the next request
   210→    if (err.code === 'ECONNREFUSED') {
   211→      _ready = false;
   212→      _starting = null;
   213→      console.log('[pipeline] Connection refused — triggering Python restart');
   214→      startPythonServer(); // don't await — let it restart in the background
   215→    }
   216→
   217→    return buildMockResult(filePath, config);
   218→  }
   219→};
   220→
   221→
   222→/**
   223→ * sendToServer — Internal: send an HTTP POST to the Python pipeline server.
   224→ *
   225→ * @param {string} filePath - Path to the resume file
   226→ * @param {object} config   - Job requirements config
   227→ * @returns {Promise<object>} - Parsed JSON response from Python
   228→ */
   229→const sendToServer = (filePath, config) => {
   230→  return new Promise((resolve, reject) => {
   231→    const payload = JSON.stringify({ file: filePath, config });
   232→
   233→    const req = http.request({
   234→      hostname: '127.0.0.1',
   235→      port: PIPELINE_PORT,
   236→      path: '/',
   237→      method: 'POST',
   238→      headers: {
   239→        'Content-Type': 'application/json',
   240→        'Content-Length': Buffer.byteLength(payload),
   241→      },
   242→      timeout: 30000, // 30s timeout for very large resumes
   243→    }, (res) => {
   244→      let body = '';
   245→      res.on('data', (chunk) => { body += chunk; });
   246→      res.on('end', () => {
   247→        try {
   248→          resolve(JSON.parse(body));
   249→        } catch (e) {
   250→          reject(new Error(`Invalid JSON from Python: ${body.substring(0, 200)}`));
   251→        }
   252→      });
   253→    });
   254→
   255→    req.on('error', reject);
   256→    req.on('timeout', () => {
   257→      req.destroy();
   258→      reject(new Error('Pipeline request timed out'));
   259→    });
   260→
   261→    req.write(payload);
   262→    req.end();
   263→  });
   264→};
   265→
   266→
   267→/**
   268→ * buildMockResult — Generate a fake but realistic result for development/fallback.
   269→ *
   270→ * Used when:
   271→ *   - Python is not installed on the machine
   272→ *   - The Python server crashed and hasn't restarted yet
   273→ *   - Any error occurs during processing
   274→ *
   275→ * The mock result uses random values within realistic ranges so the
   276→ * UI can be developed and tested without Python being set up.
   277→ *
   278→ * @param {string} filePath - Not used, but kept for signature consistency
   279→ * @param {object} config   - Used to get required skills and education
   280→ * @returns {object} - A fake candidate result object
   281→ */
   282→const buildMockResult = (filePath, config) => {
   283→  const requiredSkills = config.skills || ['python', 'machine learning', 'sql', 'nlp'];
   284→
   285→  // Pretend the candidate has 60% of the required skills
   286→  const foundSkills   = requiredSkills.slice(0, Math.ceil(requiredSkills.length * 0.6));
   287→  const missingSkills = requiredSkills.filter((s) => !foundSkills.includes(s));
   288→
   289→  const similarity = parseFloat((Math.random() * 0.4 + 0.5).toFixed(4)); // random 0.5–0.9
   290→  const experience = Math.floor(Math.random() * 5) + 1;                   // random 1–5 years
   291→  const score      = parseFloat(
   292→    (0.7 * similarity + 0.3 * Math.min(experience / 5, 1.0)).toFixed(4)
   293→  );
   294→
   295→  // Classify based on score thresholds (matches classifier.py logic)
   296→  let result = 'REJECT';
   297→  if (score >= 0.75) result = 'QUALIFIED';
   298→  else if (score >= 0.4) result = 'SHORTLIST';
   299→
   300→  return {
   301→    name:       'Candidate',  // no real name available in mock
   302→    email:      '',
   303→    phone:      '',
   304→    skills:     foundSkills,
   305→    education:  config.education || 'B.TECH',
   306→    experience,
   307→    similarity,
   308→    score,
   309→    result,
   310→    missingSkills,
   311→    suggestions: [
   312→      'Add more quantifiable achievements to your experience section.',
   313→      'Include relevant certifications to strengthen your profile.',
   314→      'Tailor your resume keywords to match the job description.',
   315→    ],
   316→    strengths: foundSkills.map((s) => `Proficient in ${s}`),
   317→    weaknesses: missingSkills.map((s) => `Missing skill: ${s}`),
   318→  };
   319→};
   320→
   321→module.exports = { runPipeline, startPythonServer, stopPythonServer };
   322→

