// Configure the main frontend workflow
const result = await configureWorkflow({
    name: "Start application",
    command: "bash start.sh",
    waitForPort: 5000,
    outputType: "webview",
    autoStart: true
});
console.log(JSON.stringify(result, null, 2));

const status = await getWorkflowStatus({ name: "Start application", maxScrollbackLines: 50 });
console.log(`State: ${status.state}`);
console.log(`Open Ports: ${JSON.stringify(status.openPorts)}`);
console.log(`Output:\n${status.output}`);

// Configure deployment as VM (needs persistent MongoDB + Python subprocess)
const result = await deployConfig({
    deploymentTarget: "vm",
    run: ["bash", "start.sh"]
});
console.log(JSON.stringify(result, null, 2));

