     3→
     4→export default function MagneticButton({ children, className = '', onClick, disabled = false, variant = 'primary' }) {
     5→  const ref = useRef(null);
     6→  const [ripple, setRipple] = useState(null);
     7→
     8→  const x = useMotionValue(0);
     9→  const y = useMotionValue(0);
    10→  const springX = useSpring(x, { stiffness: 200, damping: 20 });
    11→  const springY = useSpring(y, { stiffness: 200, damping: 20 });
    12→
    13→  const onMouseMove = (e) => {
    14→    if (disabled) return;
    15→    const rect = ref.current.getBoundingClientRect();
    16→    const centerX = rect.left + rect.width / 2;
    17→    const centerY = rect.top + rect.height / 2;
    18→    x.set((e.clientX - centerX) * 0.2);
    19→    y.set((e.clientY - centerY) * 0.2);
    20→  };
    21→
    22→  const onMouseLeave = () => {
    23→    x.set(0);
    24→    y.set(0);
    25→  };
    26→
    27→  const handleClick = (e) => {
    28→    if (disabled) return;
    29→    // Ripple effect
    30→    const rect = ref.current.getBoundingClientRect();
    31→    setRipple({
    32→      x: e.clientX - rect.left,
    33→      y: e.clientY - rect.top,
    34→      id: Date.now(),
    35→    });
    36→    setTimeout(() => setRipple(null), 600);
    37→    onClick?.(e);
    38→  };
    39→
    40→  const baseClass = variant === 'primary' ? 'btn-primary' : 'btn-secondary';
    41→
    42→  return (
    43→    <motion.button
    44→      ref={ref}
    45→      style={{ x: springX, y: springY }}
    46→      onMouseMove={onMouseMove}
    47→      onMouseLeave={onMouseLeave}
    48→      onClick={handleClick}
    49→      disabled={disabled}
    50→      whileTap={{ scale: 0.97 }}
    51→      className={`${baseClass} relative overflow-hidden ${className}`}
    52→    >
    53→      {/* Ripple */}
    54→      {ripple && (
    55→        <motion.span
    56→          key={ripple.id}
    57→          initial={{ scale: 0, opacity: 0.5 }}
    58→          animate={{ scale: 4, opacity: 0 }}
    59→          transition={{ duration: 0.6 }}
    60→          className="absolute rounded-full pointer-events-none"
    61→          style={{
    62→            left: ripple.x,
    63→            top: ripple.y,
    64→            width: 20,
    65→            height: 20,
    66→            marginLeft: -10,
    67→            marginTop: -10,
    68→            background: 'rgba(255,255,255,0.3)',
    69→          }}
    70→        />
    71→      )}
