/** @type {import('tailwindcss').Config} */
export default {
  content: ['./index.html', './src/**/*.{js,jsx,ts,tsx}'],
  theme: {
    extend: {
      colors: {
        // Deep midnight backgrounds
        space: {
          50:  '#f0f4ff',
          100: '#dce6ff',
          200: '#b8ccff',
          300: '#7fa4f8',
          400: '#4d7ef0',
          500: '#2458e0',
          600: '#1840c4',
          700: '#132f9a',
          800: '#0d1f6b',
          900: '#080e3a',
          950: '#04071e',
        },
        // Gold / amber primary brand
        brand: {
          50:  '#fffbeb',
          100: '#fef3c7',
          200: '#fde68a',
          300: '#fcd34d',
          400: '#fbbf24',
          500: '#f59e0b',
          600: '#d97706',
          700: '#b45309',
          800: '#92400e',
          900: '#78350f',
        },
        // Sky blue accent
        cyan: {
          300: '#93c5fd',
          400: '#60a5fa',
          500: '#3b82f6',
          600: '#2563eb',
        },
        // Emerald for success
        accent: {
          300: '#6ee7b7',
          400: '#34d399',
          500: '#10b981',
          600: '#059669',
        },
        // Rose for danger
        danger: {
          300: '#fda4af',
          400: '#fb7185',
          500: '#f43f5e',
          600: '#e11d48',
        },
        // Amber for warnings
        warn: {
          300: '#fcd34d',
          400: '#fbbf24',
          500: '#f59e0b',
        },
        // Surface layers
        surface: {
          50:  '#f8fafc',
          100: '#f1f5f9',
          200: '#e2e8f0',
          800: '#0d1f6b',
          900: '#080e3a',
          950: '#04071e',
        },
      },
      fontFamily: {
        display: ['Space Grotesk', 'system-ui', 'sans-serif'],
        sans:    ['Inter', 'system-ui', 'sans-serif'],
        mono:    ['JetBrains Mono', 'monospace'],
      },
      backgroundImage: {
        'hero-gradient': 'linear-gradient(135deg, #04071e 0%, #0d1f6b 40%, #080e3a 70%, #04071e 100%)',
        'card-gradient': 'linear-gradient(135deg, rgba(245,158,11,0.07) 0%, rgba(59,130,246,0.04) 100%)',
        'glow-conic':    'conic-gradient(from 180deg at 50% 50%, #f59e0b 0deg, #3b82f6 120deg, #10b981 240deg, #f59e0b 360deg)',
      },
      boxShadow: {
        'glow-sm':    '0 0 15px rgba(245,158,11,0.25)',
        'glow-md':    '0 0 30px rgba(245,158,11,0.35)',
        'glow-lg':    '0 0 60px rgba(245,158,11,0.4)',
        'glow-cyan':  '0 0 30px rgba(59,130,246,0.3)',
        'glow-accent':'0 0 30px rgba(16,185,129,0.3)',
        'card':       '0 4px 24px rgba(0,0,0,0.5), 0 0 0 1px rgba(245,158,11,0.06)',
        'card-hover': '0 12px 48px rgba(0,0,0,0.6), 0 0 0 1px rgba(245,158,11,0.18)',
        'inner-glow': 'inset 0 0 30px rgba(245,158,11,0.08)',
      },
      animation: {
        'float':       'float 6s ease-in-out infinite',
        'float-slow':  'float 8s ease-in-out infinite',
        'shimmer':     'shimmer 2s linear infinite',
        'glow-pulse':  'glow-pulse 2s ease-in-out infinite',
        'spin-slow':   'spin 3s linear infinite',
        'gradient-x':  'gradient-x 3s ease infinite',
        'border-glow': 'border-glow 3s ease-in-out infinite',
      },
      keyframes: {
        float: {
          '0%, 100%': { transform: 'translateY(0)' },
          '50%':      { transform: 'translateY(-20px)' },
        },
        shimmer: {
          '0%':   { backgroundPosition: '-200% 0' },
          '100%': { backgroundPosition: '200% 0' },
        },
        'glow-pulse': {
          '0%, 100%': { opacity: '1' },
          '50%':      { opacity: '0.5' },
        },
        'gradient-x': {
          '0%, 100%': { backgroundPosition: '0% 50%' },
          '50%':      { backgroundPosition: '100% 50%' },
        },
        'border-glow': {
          '0%, 100%': { borderColor: 'rgba(245,158,11,0.3)' },
          '50%':      { borderColor: 'rgba(59,130,246,0.5)' },
        },
      },
      transitionTimingFunction: {
        'bounce-in': 'cubic-bezier(0.68, -0.55, 0.265, 1.55)',
      },
    },
  },
  plugins: [],
}

@import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700&family=Inter:wght@300;400;500;600;700;800;900&family=JetBrains+Mono:wght@400;500&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  * {
    box-sizing: border-box;
  }

  html {
    scroll-behavior: smooth;
  }

  body {
    @apply bg-space-950 text-white font-sans antialiased;
    background-image:
      radial-gradient(ellipse at 20% 0%, rgba(245,158,11,0.07) 0%, transparent 50%),
      radial-gradient(ellipse at 80% 20%, rgba(59,130,246,0.05) 0%, transparent 50%),
      radial-gradient(ellipse at 50% 80%, rgba(16,185,129,0.03) 0%, transparent 50%);
    min-height: 100vh;
    margin: 0;
  }

  #root {
    width: 100%;
    max-width: 100%;
    margin: 0;
    text-align: left;
    border: none;
    min-height: 100vh;
    display: block;
  }

  /* Scrollbar */
  ::-webkit-scrollbar {
    width: 6px;
    height: 6px;
  }
  ::-webkit-scrollbar-track {
    background: rgba(4,7,30,0.8);
  }
  ::-webkit-scrollbar-thumb {
    background: linear-gradient(180deg, #f59e0b, #3b82f6);
    border-radius: 999px;
  }
  ::-webkit-scrollbar-thumb:hover {
    background: linear-gradient(180deg, #fbbf24, #60a5fa);
  }

  /* Selection */
  ::selection {
    background: rgba(245,158,11,0.28);
    color: #fff;
  }
}

@layer components {
  /* ─── Glass morphism ─────────────────────────────────── */
  .glass {
    @apply bg-white/[0.03] backdrop-blur-xl border border-white/[0.08];
  }

  .glass-dark {
    @apply bg-space-950/80 backdrop-blur-2xl border border-white/[0.05];
  }

  .glass-glow {
    @apply bg-white/[0.03] backdrop-blur-xl border border-brand-500/20;
    box-shadow: inset 0 0 40px rgba(245,158,11,0.04), 0 0 20px rgba(245,158,11,0.04);
  }

  /* ─── Buttons ────────────────────────────────────────── */
  .btn-primary {
    @apply inline-flex items-center justify-center gap-2 px-6 py-3 rounded-xl
           font-display font-semibold text-sm text-white
           transition-all duration-300 ease-out
           focus:outline-none focus:ring-2 focus:ring-brand-500/50 focus:ring-offset-2 focus:ring-offset-space-950
           disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:shadow-none;
    background: linear-gradient(135deg, #d97706, #b45309);
    box-shadow: 0 0 20px rgba(245,158,11,0.25), 0 4px 12px rgba(0,0,0,0.4);
  }
  .btn-primary:hover:not(:disabled) {
    background: linear-gradient(135deg, #f59e0b, #d97706);
    box-shadow: 0 0 30px rgba(245,158,11,0.4), 0 8px 24px rgba(0,0,0,0.5);
    transform: translateY(-2px);
  }
  .btn-primary:active:not(:disabled) {
    transform: translateY(0);
    box-shadow: 0 0 15px rgba(245,158,11,0.25), 0 2px 8px rgba(0,0,0,0.3);
  }

  .btn-secondary {
    @apply inline-flex items-center justify-center gap-2 px-6 py-3 rounded-xl
           font-display font-semibold text-sm text-white/90
           border border-white/10 hover:border-brand-500/40
           transition-all duration-300 ease-out
           focus:outline-none focus:ring-2 focus:ring-white/20 focus:ring-offset-2 focus:ring-offset-space-950
           disabled:opacity-50 disabled:cursor-not-allowed;
    background: rgba(255,255,255,0.05);
  }
  .btn-secondary:hover:not(:disabled) {
    background: rgba(255,255,255,0.08);
    box-shadow: 0 0 20px rgba(245,158,11,0.12);
    transform: translateY(-2px);
  }

  .btn-danger {
    @apply inline-flex items-center justify-center gap-2 px-4 py-2 rounded-lg
           bg-danger-500/15 hover:bg-danger-500/25 text-danger-400 font-display font-medium text-sm
           border border-danger-500/25 hover:border-danger-500/40
           transition-all duration-300;
  }

  .btn-success {
    @apply inline-flex items-center justify-center gap-2 px-4 py-2 rounded-lg
           bg-accent-500/15 hover:bg-accent-500/25 text-accent-400 font-display font-medium text-sm
           border border-accent-500/25 hover:border-accent-500/40
           transition-all duration-300;
  }

  /* ─── Cards ──────────────────────────────────────────── */
  .card {
    @apply glass rounded-2xl p-6 transition-all duration-500;
    box-shadow: 0 4px 24px rgba(0,0,0,0.4), 0 0 0 1px rgba(245,158,11,0.05);
  }
  .card:hover {
    border-color: rgba(245,158,11,0.2);
    box-shadow: 0 12px 48px rgba(0,0,0,0.6), 0 0 0 1px rgba(245,158,11,0.15), 0 0 30px rgba(245,158,11,0.06);
  }

  .stat-card {
    @apply glass-glow rounded-2xl p-5 flex flex-col gap-3;
  }

  /* ─── Inputs ─────────────────────────────────────────── */
  .input-field {
    @apply w-full px-4 py-3 rounded-xl bg-white/[0.04] border border-white/10
           text-white placeholder-white/25 text-sm font-sans
           transition-all duration-300;
  }
  .input-field:focus {
    @apply outline-none border-brand-500/60;
    box-shadow: 0 0 0 3px rgba(245,158,11,0.12), 0 0 20px rgba(245,158,11,0.08);
    background: rgba(255,255,255,0.06);
  }

  /* ─── Badges ─────────────────────────────────────────── */
  .badge {
    @apply inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-display font-medium;
  }
  .badge-qualified {
    @apply badge bg-accent-500/20 text-accent-400 border border-accent-500/30;
  }
  .badge-shortlist {
    @apply badge bg-warn-500/20 text-warn-400 border border-warn-500/30;
  }
  .badge-reject {
    @apply badge bg-danger-500/20 text-danger-400 border border-danger-500/30;
  }
  .badge-pending {
    @apply badge bg-white/10 text-white/60 border border-white/10;
  }
  .badge-accepted {
    @apply badge bg-brand-500/20 text-brand-400 border border-brand-500/30;
  }

  /* ─── Section typography ─────────────────────────────── */
  .section-title {
    @apply text-2xl font-display font-bold text-white;
  }
  .section-subtitle {
    @apply text-white/50 text-sm mt-1;
  }

  /* ─── Progress ───────────────────────────────────────── */
  .progress-bar {
    @apply h-2 rounded-full bg-white/[0.06] overflow-hidden;
  }
  .progress-fill {
    @apply h-full rounded-full transition-all duration-1000 ease-out;
  }

  /* ─── Skill badges ───────────────────────────────────── */
  .skill-badge {
    @apply inline-flex items-center px-3 py-1 rounded-full text-xs font-medium
           bg-brand-500/10 text-brand-300 border border-brand-500/20
           transition-all duration-300;
  }
  .skill-badge:hover {
    @apply bg-brand-500/20 border-brand-500/40;
    box-shadow: 0 0 12px rgba(245,158,11,0.2);
  }

  .skill-badge-missing {
    @apply inline-flex items-center px-3 py-1 rounded-full text-xs font-medium
           bg-danger-500/10 text-danger-300 border border-danger-500/20
           transition-all duration-300;
  }
  .skill-badge-missing:hover {
    @apply bg-danger-500/20 border-danger-500/40;
    box-shadow: 0 0 12px rgba(244,63,94,0.2);
  }

  /* ─── Table ──────────────────────────────────────────── */
  .table-row {
    @apply border-b border-white/5 hover:bg-white/[0.02] transition-colors duration-200;
  }
  .table-header {
    @apply text-xs font-display font-semibold text-white/40 uppercase tracking-wider px-4 py-3;
  }
  .table-cell {
    @apply px-4 py-3 text-sm text-white/80;
  }
}

@layer utilities {
  /* ─── Gradient text ──────────────────────────────────── */
  .text-gradient {
    @apply bg-clip-text text-transparent;
    background-image: linear-gradient(135deg, #f59e0b, #3b82f6);
  }

  .text-gradient-warm {
    @apply bg-clip-text text-transparent;
    background-image: linear-gradient(135deg, #fbbf24, #f59e0b);
  }

  .text-gradient-hero {
    @apply bg-clip-text text-transparent;
    background-image: linear-gradient(135deg, #fde68a, #93c5fd, #6ee7b7);
    background-size: 200% auto;
    animation: gradient-x 4s ease infinite;
  }

  /* ─── Grid background ────────────────────────────────── */
  .bg-grid {
    background-image:
      linear-gradient(rgba(245,158,11,0.03) 1px, transparent 1px),
      linear-gradient(90deg, rgba(245,158,11,0.03) 1px, transparent 1px);
    background-size: 60px 60px;
  }

  /* ─── Shimmer overlay ────────────────────────────────── */
  .shimmer {
    background: linear-gradient(
      90deg,
      transparent 0%,
      rgba(245,158,11,0.07) 50%,
      transparent 100%
    );
    background-size: 200% 100%;
    animation: shimmer 2s linear infinite;
  }
}

